              {tool.icon}
            </div>
            <div>
              <h2 className="text-2xl font-bold text-slate-900">{tool.name}</h2>
              <p className="text-slate-500 text-sm">{tool.description}</p>
            </div>
          </div>

          <div className="space-y-6">
